export type Customer = { yearsWithMHPCO: number };
export type Item = {
  type: string;
  material?: string;
  enchantment?: number;
  cursed?: boolean;
};
export type QuoteStep = { op: "quote"; items: Item[] };
export type Damage = { itemType: string; amount: number };
export type Incident = { cause: string; damages: Damage[] };
export type ClaimStep = { op: "claim"; policy: number; incident: Incident };
export type Step = QuoteStep | ClaimStep;
export type Scenario = { customer: Customer; steps: Step[] };

export type QuoteResult = { premium: number };
export type ClaimResult = { payout: number; remainingCap: number };
export type StepResult = QuoteResult | ClaimResult;
export type ScenarioResult = { results: StepResult[] };

const PROCESSING_FEE = 5;
const FIRST_INSURANCE_SURCHARGE_PERCENT = 10;

const BASE_PREMIUM_BY_TYPE: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
  rune: 25,
};

const itemBasePremium = (item: Item): number => BASE_PREMIUM_BY_TYPE[item.type];

const quotePremium = (step: QuoteStep): number => {
  const baseTotal = step.items.reduce((sum, item) => sum + itemBasePremium(item), 0);
  const withFirstInsurance = (baseTotal * (100 + FIRST_INSURANCE_SURCHARGE_PERCENT)) / 100;
  return Math.ceil(withFirstInsurance) + PROCESSING_FEE;
};

export const runScenario = (scenario: Scenario): ScenarioResult => {
  const results = scenario.steps.map((step) => {
    if (step.op === "quote") return { premium: quotePremium(step) };
    return { payout: 0, remainingCap: 0 };
  });
  return { results };
};

