import { describe, it, expect } from "vitest";
import { runScenario } from "./claim-office.js";

describe("MHPCO Claim Office", () => {
  describe("Quote - base premiums (with 5 G fee, newcomer first-insurance surcharge for non-empty)", () => {
    it("empty item list -> premium 5 G (only the processing fee)", () => {
      const result = runScenario({
        customer: { yearsWithMHPCO: 0 },
        steps: [{ op: "quote", items: [] }],
      });
      expect(result).toEqual({ results: [{ premium: 5 }] });
    });
    it("single plain sword for a newcomer -> 100 G base + 10 G first insurance + 5 G fee = 115 G", () => {
      const result = runScenario({
        customer: { yearsWithMHPCO: 0 },
        steps: [{ op: "quote", items: [{ type: "sword" }] }],
      });
      expect(result).toEqual({ results: [{ premium: 115 }] });
    });
    it("single plain amulet for a newcomer -> 60 G base + 6 G first insurance + 5 G fee = 71 G", () => {
      const result = runScenario({
        customer: { yearsWithMHPCO: 0 },
        steps: [{ op: "quote", items: [{ type: "amulet" }] }],
      });
      expect(result).toEqual({ results: [{ premium: 71 }] });
    });
    it("single plain staff for a newcomer -> 80 G base + 8 G first insurance + 5 G fee = 93 G", () => {
      const result = runScenario({
        customer: { yearsWithMHPCO: 0 },
        steps: [{ op: "quote", items: [{ type: "staff" }] }],
      });
      expect(result).toEqual({ results: [{ premium: 93 }] });
    });
    it("single plain potion for a newcomer -> 40 G base + 4 G first insurance + 5 G fee = 49 G", () => {
      const result = runScenario({
        customer: { yearsWithMHPCO: 0 },
        steps: [{ op: "quote", items: [{ type: "potion" }] }],
      });
      expect(result).toEqual({ results: [{ premium: 49 }] });
    });
  });

  describe("Component pricing and building blocks", () => {
    it("2 runes -> 50 G base premium (no block); full premium 60 G", () => {
      const result = runScenario({
        customer: { yearsWithMHPCO: 0 },
        steps: [{ op: "quote", items: [{ type: "rune" }, { type: "rune" }] }],
      });
      expect(result).toEqual({ results: [{ premium: 60 }] });
    });
    it("3 runes -> 60 G base premium (block applies); full 71 G", () => {
      const result = runScenario({
        customer: { yearsWithMHPCO: 0 },
        steps: [{ op: "quote", items: [{ type: "rune" }, { type: "rune" }, { type: "rune" }] }],
      });
      expect(result).toEqual({ results: [{ premium: 71 }] });
    });
    it("4 runes -> 100 G base premium (no block - block requires exactly 3); full 115 G", () => {
      const result = runScenario({
        customer: { yearsWithMHPCO: 0 },
        steps: [{ op: "quote", items: [
          { type: "rune" }, { type: "rune" }, { type: "rune" }, { type: "rune" },
        ] }],
      });
      expect(result).toEqual({ results: [{ premium: 115 }] });
    });
    it("7 runes -> 175 G base premium (no block, 7 single components); full 198 G", () => {
      const items = Array.from({ length: 7 }, () => ({ type: "rune" }));
      const result = runScenario({
        customer: { yearsWithMHPCO: 0 },
        steps: [{ op: "quote", items }],
      });
      expect(result).toEqual({ results: [{ premium: 198 }] });
    });
    it("2 runes + 1 moonstone -> 75 G base premium (no block: different types); full 88 G", () => {
      const result = runScenario({
        customer: { yearsWithMHPCO: 0 },
        steps: [{ op: "quote", items: [
          { type: "rune" }, { type: "rune" }, { type: "moonstone" },
        ] }],
      });
      expect(result).toEqual({ results: [{ premium: 88 }] });
    });
    it("3 runes + 3 moonstones -> 120 G base premium (two separate blocks); full 137 G", () => {
      const result = runScenario({
        customer: { yearsWithMHPCO: 0 },
        steps: [{ op: "quote", items: [
          { type: "rune" }, { type: "rune" }, { type: "rune" },
          { type: "moonstone" }, { type: "moonstone" }, { type: "moonstone" },
        ] }],
      });
      expect(result).toEqual({ results: [{ premium: 137 }] });
    });
  });

  describe("Premium modifiers - item-specific", () => {
    it("cursed sword (newcomer) -> 100 + 50 curse + 10 first ins = 160 + 5 fee = 165 G", () => {
      const result = runScenario({
        customer: { yearsWithMHPCO: 0 },
        steps: [{ op: "quote", items: [{ type: "sword", cursed: true }] }],
      });
      expect(result).toEqual({ results: [{ premium: 165 }] });
    });
    it("sword with enchantment exactly 5 -> high-ench surcharge (100 + 30 + 10 + 5 = 145)", () => {
      const result = runScenario({
        customer: { yearsWithMHPCO: 0 },
        steps: [{ op: "quote", items: [{ type: "sword", enchantment: 5 }] }],
      });
      expect(result).toEqual({ results: [{ premium: 145 }] });
    });
    it("sword with enchantment 4 -> no high-ench surcharge (115 G as plain)", () => {
      const result = runScenario({
        customer: { yearsWithMHPCO: 0 },
        steps: [{ op: "quote", items: [{ type: "sword", enchantment: 4 }] }],
      });
      expect(result).toEqual({ results: [{ premium: 115 }] });
    });
    it("cursed sword ench 5 -> both: 100 + 50 + 30 + 10 + 5 = 195", () => {
      const result = runScenario({
        customer: { yearsWithMHPCO: 0 },
        steps: [{ op: "quote", items: [{ type: "sword", cursed: true, enchantment: 5 }] }],
      });
      expect(result).toEqual({ results: [{ premium: 195 }] });
    });
  });

  describe("Premium modifiers - policy-wide", () => {
    it("long-standing customer (3 years), plain sword -> 100 - 20 loyalty + 10 first-ins + 5 fee = 95", () => {
      const result = runScenario({
        customer: { yearsWithMHPCO: 3 },
        steps: [{ op: "quote", items: [{ type: "sword" }] }],
      });
      expect(result).toEqual({ results: [{ premium: 95 }] });
    });
    it.todo("customer with exactly 2 years -> loyalty discount applies");
    it.todo("first quote of scenario -> no follow-up contract discount");
    it.todo("second quote of scenario -> 15% follow-up contract discount");
  });

  describe("Modifier scope on multi-item policies", () => {
    it.todo("cursed sword + plain amulet (newcomer): base 160, +50 curse, +16 first ins, +5 fee = 231 G");
  });

  describe("Rounding (in MHPCO favor)", () => {
    it.todo("premium 197.5 G -> 198 G (rounded up)");
    it.todo("payout 350.5 G -> 350 G (rounded down)");
  });

  describe("Integration examples", () => {
    it.todo("newcomer with cursed sword (steel, ench 3) -> premium 165 G");
    it.todo("long-standing customer's second contract: cursed sword ench 7, 3 years -> premium 160 G");
  });

  describe("Claim - basic reimbursement", () => {
    it.todo("regular sword (steel, ench 3), damage 500 G -> payout 400 G (500 - 100 deductible)");
    it.todo("damage to a rune (ins value 250), damage 200 G -> payout 100 G");
  });

  describe("Claim - high-enchantment clause", () => {
    it.todo("steel sword ench 9, damage 1000 -> payout 400 (50% then 100 deductible)");
    it.todo("dragon-material sword ench 8, damage 1000 -> payout 400 (high-ench wins, then deductible)");
    it.todo("dragon-material sword ench 9, damage 1000 -> payout 400 (50% wins, then deductible)");
  });

  describe("Claim - dragon material clause", () => {
    it.todo("dragon-material sword ench 5, damage 800 -> payout 700 (full reimbursement, then deductible)");
  });

  describe("Claim - deductible per damage event", () => {
    it.todo("dragon attack: sword 500 + amulet 300 -> payout 600 (100 deductible per item)");
  });

  describe("Claim - multiple items of same type", () => {
    it.todo("policy with two swords: insurance sum 2000 G, cap 4000 G");
    it.todo("dragon attack damages both swords as two entries -> each treated as separate damage");
    it.todo("damages array has more entries of a type than policy covers -> claim rejected (non-zero exit)");
  });

  describe("Claim - cap exhaustion", () => {
    it.todo("policy sword + amulet: insurance sum 1600 G, cap 3200 G");
    it.todo("cursed sword (ins value 1000) -> cap 2000 G (based on unmodified ins value)");
    it.todo("policy sword + 3 runes (block): insurance sum 1750 G (block affects premium only)");
    it.todo("sword (cap 2000): two claims of 1500 G -> first payout 1400, then 600 (cap exhausted)");
  });

  describe("CLI error cases", () => {
    it.todo("quote with unknown item type -> CLI exits non-zero with error to stderr");
    it.todo("claim references damage entry for item not in policy -> CLI exits non-zero");
    it.todo("claim with damage amount -200 -> CLI exits non-zero");
  });

  describe("CLI happy path (stdin/stdout JSON)", () => {
    it.todo("schema example: quote amulet then claim 200 G -> {premium, payout, remainingCap}");
  });
});

