1	export type Customer = { yearsWithMHPCO: number };
2	export type Item = {
3	  type: string;
4	  material?: string;
5	  enchantment?: number;
6	  cursed?: boolean;
7	};
8	export type QuoteStep = { op: "quote"; items: Item[] };
9	export type Damage = { itemType: string; amount: number };
10	export type Incident = { cause: string; damages: Damage[] };
11	export type ClaimStep = { op: "claim"; policy: number; incident: Incident };
12	export type Step = QuoteStep | ClaimStep;
13	export type Scenario = { customer: Customer; steps: Step[] };
14	
15	export type QuoteResult = { premium: number };
16	export type ClaimResult = { payout: number; remainingCap: number };
17	export type StepResult = QuoteResult | ClaimResult;
18	export type ScenarioResult = { results: StepResult[] };
19	
20	const PROCESSING_FEE = 5;
21	const FIRST_INSURANCE_SURCHARGE_PERCENT = 10;
22	const COMPONENT_BLOCK_SIZE = 3;
23	const COMPONENT_BLOCK_PREMIUM = 60;
24	const INSURANCE_VALUE_PER_PREMIUM = 10;
25	
26	const BASE_PREMIUM_BY_TYPE: Record<string, number> = {
27	  sword: 100,
28	  amulet: 60,
29	  staff: 80,
30	  potion: 40,
31	  rune: 25,
32	  moonstone: 25,
33	};
34	
35	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
36	const isComponent = (item: Item): boolean => COMPONENT_TYPES.has(item.type);
37	
38	const CURSE_SURCHARGE_PERCENT = 50;
39	const HIGH_ENCHANTMENT_THRESHOLD = 5;
40	const HIGH_ENCHANTMENT_SURCHARGE_PERCENT = 30;
41	const LOYALTY_YEARS_THRESHOLD = 2;
42	const LOYALTY_DISCOUNT_PERCENT = 20;
43	const FOLLOW_UP_DISCOUNT_PERCENT = 15;
44	const DEDUCTIBLE = 100;
45	const CAP_MULTIPLIER = 2;
46	const ENCHANTED_CLAIM_THRESHOLD = 8;
47	const ENCHANTED_REIMBURSEMENT_PERCENT = 50;
48	
49	const itemBasePremium = (item: Item): number => {
50	  const premium = BASE_PREMIUM_BY_TYPE[item.type];
51	  if (premium === undefined) throw new Error(`Unknown item type: ${item.type}`);
52	  return premium;
53	};
54	
55	const itemInsuranceValue = (item: Item): number =>
56	  itemBasePremium(item) * INSURANCE_VALUE_PER_PREMIUM;
57	
58	const itemSurchargePercent = (item: Item): number => {
59	  let pct = 0;
60	  if (item.cursed) pct += CURSE_SURCHARGE_PERCENT;
61	  if ((item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD) pct += HIGH_ENCHANTMENT_SURCHARGE_PERCENT;
62	  return pct;
63	};
64	
65	const itemSurcharge = (item: Item): number =>
66	  (itemBasePremium(item) * itemSurchargePercent(item)) / 100;
67	
68	const groupByType = <T extends { type: string }>(items: T[]): Map<string, T[]> => {
69	  const grouped = new Map<string, T[]>();
70	  for (const item of items) {
71	    const list = grouped.get(item.type) ?? [];
72	    list.push(item);
73	    grouped.set(item.type, list);
74	  }
75	  return grouped;
76	};
77	
78	const componentsBaseTotal = (components: Item[]): number => {
79	  let total = 0;
80	  for (const sameTypeComponents of groupByType(components).values()) {
81	    if (sameTypeComponents.length === COMPONENT_BLOCK_SIZE) {
82	      total += COMPONENT_BLOCK_PREMIUM;
83	    } else {
84	      total += sameTypeComponents.reduce((sum, item) => sum + itemBasePremium(item), 0);
85	    }
86	  }
87	  return total;
88	};
89	
90	const policyModifierPercent = (customer: Customer, isFollowUp: boolean): number => {
91	  let pct = FIRST_INSURANCE_SURCHARGE_PERCENT;
92	  if (customer.yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD) pct -= LOYALTY_DISCOUNT_PERCENT;
93	  if (isFollowUp) pct -= FOLLOW_UP_DISCOUNT_PERCENT;
94	  return pct;
95	};
96	
97	const quotePremium = (step: QuoteStep, customer: Customer, isFollowUp: boolean): number => {
98	  const components = step.items.filter(isComponent);
99	  const mainItems = step.items.filter((i) => !isComponent(i));
100	  const policyBase =
101	    mainItems.reduce((sum, item) => sum + itemBasePremium(item), 0) +
102	    componentsBaseTotal(components);
103	  const itemSurcharges = mainItems.reduce((sum, item) => sum + itemSurcharge(item), 0);
104	  const policyModifiers = (policyBase * policyModifierPercent(customer, isFollowUp)) / 100;
105	  const total = policyBase + itemSurcharges + policyModifiers;
106	  return Math.ceil(total) + PROCESSING_FEE;
107	};
108	
109	type Policy = { items: Item[]; remainingCap: number };
110	
111	const damagePayout = (damageAmount: number, item: Item): number => {
112	  const ench = item.enchantment ?? 0;
113	  const reimbursed =
114	    ench >= ENCHANTED_CLAIM_THRESHOLD
115	      ? (damageAmount * ENCHANTED_REIMBURSEMENT_PERCENT) / 100
116	      : damageAmount;
117	  return Math.max(0, reimbursed - DEDUCTIBLE);
118	};
119	
120	const processClaim = (step: ClaimStep, policies: Map<number, Policy>): ClaimResult => {
121	  const policy = policies.get(step.policy);
122	  if (!policy) throw new Error(`No policy at step ${step.policy}`);
123	  const availableByType = groupByType(policy.items);
124	  let totalPayout = 0;
125	  for (const damage of step.incident.damages) {
126	    if (damage.amount < 0) throw new Error(`Negative damage amount: ${damage.amount}`);
127	    const item = availableByType.get(damage.itemType)?.shift();
128	    if (!item) throw new Error(`Damage references item not in policy: ${damage.itemType}`);
129	    totalPayout += damagePayout(damage.amount, item);
130	  }
131	  const payout = Math.floor(Math.min(totalPayout, policy.remainingCap));
132	  policy.remainingCap -= payout;
133	  return { payout, remainingCap: policy.remainingCap };
134	};
135	
136	const insuranceSum = (items: Item[]): number =>
137	  items.reduce((sum, item) => sum + itemInsuranceValue(item), 0);
138	
139	export const runScenario = (scenario: Scenario): ScenarioResult => {
140	  let quoteCount = 0;
141	  const policies = new Map<number, Policy>();
142	  const results: StepResult[] = scenario.steps.map((step, index) => {
143	    if (step.op === "quote") {
144	      const isFollowUp = quoteCount > 0;
145	      quoteCount += 1;
146	      const sum = insuranceSum(step.items);
147	      policies.set(index, { items: step.items, remainingCap: sum * CAP_MULTIPLIER });
148	      return { premium: quotePremium(step, scenario.customer, isFollowUp) };
149	    }
150	    return processClaim(step, policies);
151	  });
152	  return { results };
153	};
